let currentPage = 1;
const pageSize = 50;
let searchQuery = "";

// --- 1. SEARCH LOGIC ---
document.getElementById("table-search").oninput = e => {
  searchQuery = e.target.value.toLowerCase();
  currentPage = 1; // Reset to page 1 on search
  render();
};

// --- 2. DOWNLOAD LOGIC (CSV Export) ---
document.getElementById("download-btn").onclick = () => {
  const data = getFilteredData();
  if (data.length === 0) return;
  const headers = Object.keys(data[0]).join(",");
  const rows = data.map(row => Object.values(row).map(v => `"${String(v).replace(/"/g, '""')}"`).join(",")).join("\n");
  const csvContent = "data:text/csv;charset=utf-8," + headers + "\n" + rows;
  const link = document.createElement("a");
  link.setAttribute("href", encodeURI(csvContent));
  link.setAttribute("download", `PO_Export_${new Date().getTime()}.csv`);
  document.body.appendChild(link);
  link.click();
  document.body.removeChild(link);
};
function getFilteredData() {
  const allData = appsmith.model.tableData || [];
  if (!searchQuery) return allData;
  return allData.filter(row => Object.values(row).some(val => String(val).toLowerCase().includes(searchQuery)));
}
function render() {
  const filteredData = getFilteredData();
  const columns = appsmith.model.columns || [];
  const totalPages = Math.ceil(filteredData.length / pageSize) || 1;
  const start = (currentPage - 1) * pageSize;
  const pageData = filteredData.slice(start, start + pageSize);
  document.getElementById("data-count").innerText = `${filteredData.length} POs`;

  // Render Headers (adding an "Actions" column at the end)
  const headerRow = document.getElementById("header-row");
  headerRow.innerHTML = columns.map(col => `<th>${col.label}</th>`).join("") + `<th>Actions</th>`;

  // Render Body
  const tableBody = document.getElementById("table-body");
  tableBody.innerHTML = pageData.map((item, idx) => {
    return `
            <tr>
                ${columns.map(col => {
      let val = item[col.key];
      if (col.key.includes('total')) val = "₹" + parseFloat(val).toLocaleString();
      if (col.key === 'status') {
        const cls = val === 'Draft' ? 'badge-exhausted' : 'badge-available';
        val = `<span class="badge ${cls}">${val}</span>`;
      }
      return `<td>${val}</td>`;
    }).join("")}
                <td class="icon-cell">
                    <button class="btn-icon" onclick="handleAction('view', ${start + idx})" title="View PO">👁</button>
                    ${item.status === 'Draft' ? `<button class="btn-icon btn-grn" onclick="handleAction('grn', ${start + idx})" title="Create GRN">➕</button>` : ''}
                    <button class="btn-icon" onclick="handleAction('pdf', ${start + idx})" title="Download PDF">📄</button>
                </td>
            </tr>
        `;
  }).join("");

  // Update pagination UI
  document.getElementById("page-info").innerText = `Page ${currentPage} of ${totalPages}`;
}
window.handleAction = (type, originalIdx) => {
  const row = getFilteredData()[originalIdx];
  appsmith.updateModel({
    triggeredRow: row
  });
  if (type === 'view') appsmith.triggerEvent("onViewClick");
  if (type === 'grn') appsmith.triggerEvent("onCreateGRNClick");
  if (type === 'pdf') appsmith.triggerEvent("onPDFClick");
};

// ... Prev/Next button logic ...
appsmith.onModelChange(() => render());

